var e=JSON.parse(`[{"id":"L5_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"크하핫! 이래가지고 날 죽일 수야 있겠어?","JPN":"くははっ！　そんなんでアタシを殺せるのか？","ENG":"Kahaha! You think that's enough to kill me?","TWN":"哈哈哈！這樣能把我殺了嗎？"},"stage":{"bg":"FLOOR_FACILITY_03","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_LAUGH"}}},"sfx":"FX_COMBAT_ALL_MOVEMENT_05"},{"id":"L6_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"나한테 이건 싸움 축에도 못 낀다고…!","JPN":"こんなの戦いのうちにも入らないぞ……！","ENG":"This doesn't even count as a fight to me...!","TWN":"對我來說這根本稱不上是戰鬥…！"},"stage":{"bg":"FLOOR_FACILITY_03","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_PRIDE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L8_1","type":"dialog","speaker":"JAKE_DELTA_NEXT_NULL","text":{"KOREA":"유감이지만 군율 상 싸움은 금지되어 있거든.","JPN":"残念だが、軍の規律上喧嘩は禁止されていてね。","ENG":"Sorry, but per regulations, fighting's prohibited.","TWN":"雖然很遺憾，但軍規上禁止打鬥。"},"stage":{"bg":"FLOOR_FACILITY_03","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL"},{"id":"L9_1","type":"dialog","speaker":"JAKE_DELTA_NEXT_NULL","text":{"KOREA":"단둘이서 하는 데이트는… 다음으로 미루자고!","JPN":"2人きりのデートは……また今度な！","ENG":"Let's postpone our one-on-one date... till later!","TWN":"兩個人單獨約會…就推遲到下次吧！"},"stage":{"bg":"FLOOR_FACILITY_03","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NEXT_NULL","face":"UNIT_SERIOUS"},"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"JAKE_DELTA_NEXT_NULL","text":{"KOREA":"라이트닝──! 익스큐션──!!","JPN":"ライトニング───！　エクスキューージョン！！","ENG":"Lightning──! Execution──!!","TWN":"雷光──！處刑──！！"},"stage":{"bg":"FLOOR_FACILITY_03","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"JAKE_DELTA_NEXT_NULL","text":{"KOREA":"후우…….","JPN":"ふう……","ENG":"Whew...","TWN":"呼……"},"stage":{"bg":"FLOOR_FACILITY_03","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_ELECTRIC_03"},{"id":"L18_1","type":"dialog","speaker":"JAKE_DELTA_NEXT_NULL","text":{"KOREA":"저 아가씨가 상층에서 내려왔다면 승강기를 쓸 수 있다는 소리겠지.","JPN":"あのお嬢ちゃんが上層から降りてきたってことは、昇降機は使えるようになってるな。","ENG":"If that girl came down from the upper level, the elevator must be usable.","TWN":"要是那個小姐從上層下來的話，就代表能用電梯了吧。"},"stage":{"bg":"FLOOR_FACILITY_03","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"JAKE_DELTA_NEXT_NULL","text":{"KOREA":"본부 쪽 움직임이 없었던 걸 보면 승강기에 문제가 있을 순 있지만, 다이브 부하야 견디면 그만이야.","JPN":"本部側の動きがなかったからまだ問題があるかもしれないが、ダイブの負荷は耐えればいい。","ENG":"HQ hasn't moved, so the elevator might be janky, but I can tank the dive load.","TWN":"看本部那邊毫無動靜，可能是電梯有問題，但只要撐過躍入負荷就好。"},"stage":{"bg":"FLOOR_FACILITY_03","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"JAKE_DELTA_NEXT_NULL","text":{"KOREA":"서두르지 않으면 카일과 실비아가…….","JPN":"急がないとカイルとシルビアが……","ENG":"If I don't hurry, Kyle and Sylvia will...","TWN":"要是不快一點，凱爾和希爾維亞……"},"stage":{"bg":"FLOOR_FACILITY_03","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NEXT_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"JAKE_DELTA_NEXT_NULL","text":{"KOREA":"……이런.","JPN":"……おっと。","ENG":"...Well, great.","TWN":"……天哪，"},"stage":{"bg":"FLOOR_FACILITY_03","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NEXT_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L23_1","type":"dialog","speaker":"JAKE_DELTA_NEXT_NULL","text":{"KOREA":"이정도로 야성미 넘치는 레이디인 줄 몰랐는데.","JPN":"ここまでワイルドなレディーとは思わなかったが。","ENG":"Didn't know you were such a wild one.","TWN":"沒想到妳是這麼充滿野性的小姐。"},"stage":{"bg":"FLOOR_FACILITY_03","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"방금 공격은 제법이었다.","JPN":"さっきの攻撃はなかなかのものだった。","ENG":"That last strike wasn't that bad.","TWN":"剛才的攻擊很不錯。"},"stage":{"bg":"FLOOR_FACILITY_03","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"이 정도면…… 싸움이라고 부를 수준은 되겠어.","JPN":"これで……戦いといえるレベルにはなったな。","ENG":"At this level... I'll call it a real fight.","TWN":"這樣的話……水準應該能稱得上是戰鬥。"},"stage":{"bg":"FLOOR_FACILITY_03","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"YUMA_WOLF_NAME_YUMA","text":{"KOREA":"오래간만에 흥이 올랐어.","JPN":"久々に燃えてきた。","ENG":"Been a while since I felt this fired up.","TWN":"好久沒這麼有興致了。"},"stage":{"bg":"FLOOR_FACILITY_03","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_WOLF_NAME_YUMA","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L29_1","type":"dialog","speaker":"YUMA_WOLF_NAME_YUMA","text":{"KOREA":"네가 가진 능력으로, 날 더 재미있게 해보라고.","JPN":"あんたの能力で、もっとアタシを楽しませろ。","ENG":"Make it fun for me with everything you've got.","TWN":"用你擁有的能力，試著讓我更愉快吧。"},"stage":{"bg":"FLOOR_FACILITY_03","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_WOLF_NAME_YUMA","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"……여, 여기도 없죠?","JPN":"……こ、ここもいませんよね？","ENG":"...N-no one here either, right?","TWN":"……這、這裡也沒有吧？"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_COMBAT_ALL_MOVEMENT_03"},{"id":"L34_1","type":"dialog","speaker":"XIEN_FREEDOM_NULL_NULL","text":{"KOREA":"걱정 말게, 친구. 여기라면 침식체들이 눈치채지 못할 거야.","JPN":"心配するな、友よ。ここなら侵食体に気づかれずに済む。","ENG":"Don't fret, my friend. The C.O.s won't notice us here.","TWN":"別擔心，朋友，跑來這裡，侵蝕體不會發現的。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIEN_FREEDOM_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"피난민들이 남아있냐는 소리예요! 아까부터 웅크려 있지만 말고 제대로 살피라고요!","JPN":"残ってる避難民はいないかってことですよ！　うずくまってないで、ちゃんと見てください！","ENG":"I mean are there evacuees left?! Stop crouching and actually look!","TWN":"我的意思是還有難民嗎！不要從剛才開始就縮在那裡，要仔細觀察！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L39_1","type":"dialog","speaker":"XIEN_FREEDOM_NULL_NULL","text":{"KOREA":"훗훗. 무릇 호걸이라면 장소를 살피지 않고 안정을 취하는 법이지.","JPN":"ふふっ。豪傑は場所を問わず休憩を取るもの。","ENG":"Hmph. A true hero rests first and surveys later.","TWN":"呵呵，好漢通常不會觀察地點，而是會保持冷靜。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIEN_FREEDOM_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"XIEN_FREEDOM_NULL_NULL","text":{"KOREA":"이건 절대… 다, 다리가 풀린 게 아니라구.","JPN":"決して……ひ、膝が笑ってるわけではないぞ。","ENG":"And this is definitely not... b-because my legs are giving out.","TWN":"這絕對…不、不是雙腿無力。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIEN_FREEDOM_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"일 년에 한 번 올까 말까 한 호의호식이 어쩌다 공포게임으로 변질된 걸까요…….","JPN":"1年に1回来るか来ないかという豪遊のチャンスが、どうしてホラゲーに変わってしまったんでしょう……","ENG":"How did a once-in-a-year luxury trip turn into a horror game...?","TWN":"一年難得一見的好康，怎麼會變質成恐怖遊戲呢……"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L44_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"컨티뉴 버튼… 되돌아갈 수 있는 세이브 데이터가 필요해요…….","JPN":"コンティニューボタン……過去に戻れるセーブデータがほしいです……","ENG":"I need a Continue button... A save file to roll back to...","TWN":"繼續鍵…需要能恢復的保存數據……"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"민서, 쉿!","JPN":"ヒミコさん、しーっ！","ENG":"Minseo, shh!","TWN":"旼序，噓！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"아아… 침식체가 벌써 여기까지 쫓아오다니…….","JPN":"ああ……もう侵食体がここまで追ってきた……","ENG":"Ah... The C.O.s already chased us here...","TWN":"啊啊…侵蝕體居然已經追來這裡……"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"XIEN_FREEDOM_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"MINISTRA_CORRUPT_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"XIEN_FREEDOM_NULL_NULL","text":{"KOREA":"다, 다리에 쥐가 나지만 않았어도 내가 나설 텐데, 이것 참 아쉽군.","JPN":"あ、脚がしびれてなければ私が前に出たいところだが、悔しいな。","ENG":"I-I'd step up if not for this leg cramp. What a shame.","TWN":"要、要是腿沒抽筋，我就會出手，真可惜。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"XIEN_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"MINISTRA_CORRUPT_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"……아뇨.","JPN":"……いいえ。","ENG":"...No.","TWN":"……不，"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_COMBAT_ALL_SWORD_MOVEMENT"},{"id":"L7_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"저 침식체는 제가 어떻게든 따돌릴 테니, 두 분은 여기 조용히 숨어 계세요.","JPN":"あの侵食体は秋がなんとか撒いてみますから、2人はここで静かに隠れていてください。","ENG":"I'll draw it off somehow. You two stay hidden and quiet.","TWN":"我會想辦法甩掉那個侵蝕體，兩位就先安靜地躲在這裡吧。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_HERO_CHORUS_MUTE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"아키 혼자서 뭘 어쩌게요…?","JPN":"秋さん1人でどうするつもりですか……？","ENG":"Aki, what can you even do by yourself...?","TWN":"廣瀨秋一個人要幹嘛…？"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_HERO_CHORUS_MUTE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"여기서 제가 제일 빠르잖아요. 다같이 죽는 것보단 뭐라도 해보는 게 낫겠죠.","JPN":"この中じゃ秋が一番速いじゃないですか。全滅するよりは、何かしらやってみたほうがいいでしょう。","ENG":"I'm the fastest here. Better to try something than die together.","TWN":"這裡我動作最快，比起大家一起死，至少做些什麼會比較好吧。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_HERO_CHORUS_MUTE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"으으…….","JPN":"うう……","ENG":"Ugh...","TWN":"呃呃……"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_HERO_CHORUS_MUTE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"그럼 하다못해… 아키 양을 위해 저희만의 의식을 치르죠.","JPN":"じゃあ、せめて……ヒミコたちは秋さんのための儀式を行います。","ENG":"Then at least... let's hold a little rite for Aki.","TWN":"那實在沒辦法了…就為廣瀨秋小姐舉行專屬我們的儀式吧。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_HERO_CHORUS_MUTE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_SERIOUS"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L14_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"전 아키가 살아 돌아오지 못한다에 초코바 두 개를 걸게요…….","JPN":"ヒミコは、秋さんは生きて帰って来れないにチョコレートバー2つを賭けます……","ENG":"I bet two chocolate bars she doesn't make it back...","TWN":"我賭兩個巧克力棒，賭廣瀨秋沒辦法活著回來……"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_HERO_CHORUS_MUTE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"전 운이 없으니, 이러면 아키가 무사히 돌아오겠죠…….","JPN":"ヒミコは運がないから、こうしておけば秋さんが無事に帰ってくるはず……","ENG":"I'm unlucky, so this way she will come back safe...","TWN":"我運氣不好，這樣廣瀨秋應該會平安回來吧……"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_HERO_CHORUS_MUTE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"민서 양? 어째 평소보다 하나 더 걸지 않았어요?","JPN":"ヒミコさん？　いつもより1つ多く賭けてませんか？","ENG":"Minseo? Didn't you bet one more than usual?","TWN":"旼序小姐？怎麼沒有比平常多賭一個？"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_HERO_CHORUS_MUTE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"XIEN_FREEDOM_NULL_NULL","text":{"KOREA":"이런, 늦었군. 나도 거기에 걸려 했는데.","JPN":"やれやれ、ひと足遅かったか。私もそれに賭けるつもりだったのに。","ENG":"Drat, too late. I wanted in on that wager.","TWN":"哎呀，晚了一步，我本來也想賭那個的。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_HERO_CHORUS_MUTE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIEN_FREEDOM_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"후후. 이런 건 빠른 사람이 임자라고요.","JPN":"ふふ。こういうのは早いもの勝ちなんです。","ENG":"Haha. First come, first served.","TWN":"呵呵，這種事就是先搶先贏。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_HERO_CHORUS_MUTE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_HERO_CHORUS_MUTE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"후우…….","JPN":"ふう……","ENG":"Whew...","TWN":"呼……"},"stage":{"bg":"BLACK","bgm":"THEMA_HERO_CHORUS_MUTE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT_02"},{"id":"L23_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"할 수 있어, 아키. 네가 침식체의 이목을 끌면 민서와 시엔 씨는 무사할 거야.","JPN":"できるよ、秋。秋が侵食体の注意を引けば、ヒミコさんとシエンさんは助かる。","ENG":"You can do this, Aki. If you draw aggro, Minseo and Xien will be fine.","TWN":"妳可以的，廣瀨秋。要是妳吸引侵蝕體的注意，旼序和西恩就會平安無事。"},"stage":{"bg":"BLACK","bgm":"THEMA_HERO_CHORUS_MUTE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"그리고 여기서 활약하면, 델타세븐에게 받기로 한 보상금의 배분에서 유리할 테니…….","JPN":"それに、ここで活躍したらデルタセブンから受け取る予定の報酬を配分する時、有利になるから……","ENG":"And if I shine here, Delta Seven's reward split might tilt my way...","TWN":"而且要是在這裡表現活躍，說好要從第七三角洲那裡拿到的報酬分配應該會比較有利……"},"stage":{"bg":"BLACK","bgm":"THEMA_HERO_CHORUS_MUTE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"어쩌면 평생 불로소득으로 놀고먹을 수 있을지도?","JPN":"もしかしたら、不労所得で一生楽できるかも？","ENG":"Maybe I can live off passive income forever?","TWN":"說不定可以一輩子遊手好閒？"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_HERO_CHORUS_MUTE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT_02"},{"id":"L27_1","type":"dialog","speaker":"MINISTRA_CORRUPT_NULL_NULL","text":{"KOREA":"아직 남아있는 인간이 있었나.","JPN":"まだ人間が残っていたか。","ENG":"So a human remained.","TWN":"還有剩下的人類嗎？"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_HERO_CHORUS_MUTE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINISTRA_CORRUPT_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_MONSTER_MINISTRA_DAMAGE_DOWN"},{"id":"L28_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"응?","JPN":"え？","ENG":"Huh?","TWN":"嗯？"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_COMBAT_ALL_MOVEMENT_03"},{"id":"L30_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"꺄아아아악–! 사람 살려어어어어–––––!!!","JPN":"きゃああああ！　助けてぇぇぇぇ！！！","ENG":"Kyaaaaa–! Somebody save meeeeee–––––!!!","TWN":"呃啊啊啊啊啊–！救命啊啊啊啊–––––！！！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_TALK_08","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_WIND2"},{"id":"L34_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"아, 아아…….","JPN":"あ、ああ……","ENG":"A-ah...","TWN":"啊、啊啊……"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_TALK_08","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINISTRA_CORRUPT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"MINISTRA_CORRUPT_NULL_NULL","text":{"KOREA":"후후. 두려워하지 말려무나.","JPN":"ふふ、恐れるな。","ENG":"Haha. Do not fear.","TWN":"呵呵，別害怕。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_TALK_08","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINISTRA_CORRUPT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"MINISTRA_CORRUPT_NULL_NULL","text":{"KOREA":"내가 주는 고통을 이겨내면, 자매들과 하나되는 황홀함을 만끽할 거야.","JPN":"余の与える苦痛に耐えれば、姉妹たちと一つになる愉悦を味わえるだろう。","ENG":"Endure my bliss of pain, and you will be one with my sisters where ecstasy awaits.","TWN":"要是戰勝我帶來的痛苦，妳就會享受和姐妹們融為一體的狂喜。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_TALK_08","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINISTRA_CORRUPT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"호호, 혹시 돌아가서 생각해봐도 될까요? 자자, 잠시 생각할 시간이 필요할 것 같은데?","JPN":"す、す、すみませんが帰ってもう一度考えてみてもいいですか？　ちょちょ、ちょっと悩む時間が必要かも？","ENG":"C-c-can I sleep on it? I-I need a minute to think.","TWN":"呵呵，我可以回去再考慮一下嗎？我好像需要時間考慮耶？"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_TALK_08","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINISTRA_CORRUPT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"MINISTRA_CORRUPT_NULL_NULL","text":{"KOREA":"이리 오렴.","JPN":"おいで。","ENG":"Come here.","TWN":"過來吧。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_TALK_08","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINISTRA_CORRUPT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_COMBAT_ALL_MOVEMENT_01"},{"id":"L41_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"아아아악! 민서 양! 린 시엔 씨! 저 좀 살려주세요오오오!!","JPN":"ああああっ！　ヒミコさん！　シエンさん！　助けてくださいぃぃぃ！！","ENG":"Aaaah! Minseo! Lin Xien! Please save meee!!","TWN":"啊啊啊啊！旼序小姐！西恩！拜託救救我！！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_TALK_08","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L43_1","type":"narration","speaker":null,"text":{"KOREA":"그 순간, 아키는 보았다.","JPN":"その瞬間、秋は見た。","ENG":"In that instant, Aki saw it.","TWN":"那一刻，廣瀨秋看到了。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_TALK_08","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"narration","speaker":null,"text":{"KOREA":"저 멀리… 둘 사이에 초코바가 오가는 모습을.","JPN":"遠く……2人の間でチョコレートバーが行き交う光景を。","ENG":"Far off, the two of them... passing chocolate bars.","TWN":"遠處…兩個人交換巧克力棒的樣子。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_TALK_08","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"XIEN_FREEDOM_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L50_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"끝났다, 내 인생.","JPN":"秋の人生、終わった。","ENG":"I'm finished. My life is over.","TWN":"我的人生結束了。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_TALK_08","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_HATE"},"C":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"XIEN_FREEDOM_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L1_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"여기가 바로 지옥… 하염없이 불타는 초고열 불구덩이구나…….","JPN":"ここが地獄……永遠に燃える超高熱の火の中なのね……","ENG":"So this is hell... an endlessly blazing, ultra-hot furnace...","TWN":"原來這裡就是地獄…無止盡燃燒的超高熱火坑啊……"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_TALK_08","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_HATE"},"C":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_DESPAIR"},"R":{"char_id":"XIEN_FREEDOM_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L6_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"어라, 아직 안 죽었는데도 뜨겁네?","JPN":"あれ、まだ死んでないのに熱い？","ENG":"Huh? Why's it hot even before I'm dead?","TWN":"咦？還沒死也覺得好燙啊？"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L9_1","type":"dialog","speaker":null,"text":{"KOREA":"네가 죽으면 조직의 50% 지분이 날아가버리는 셈이잖냐.","JPN":"貴様が死ぬと組織の持ち分の5割が飛んでしまうじゃないか。","ENG":"If you die, half our organization's equity goes up in smoke.","TWN":"要是妳死了，組織50%的持股不就等於飛了嗎？"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FIRE"},{"id":"L10_1","type":"dialog","speaker":null,"text":{"KOREA":"뭐, 지분이 아니더라도 <color=#ffd34c>오오가미 흑막조</color>는 절대 동료를 버리지 않지만.","JPN":"まあ、それが理由じゃなくても<color=#ffd34c>大神黒幕組</color>は決して仲間を見捨てないがな。","ENG":"Not that it's about equity. <color=#ffd34c>Ogami's Shadow Group</color> never abandons comrades.","TWN":"就算不是持股，<color=#ffd34c>大神組</color>也絕對不會拋棄同伴。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"지금이다, 미나토!!","JPN":"今だ、湊！！","ENG":"Now, Minato!!","TWN":"就是現在，南裕夏！！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MINISTRA_CORRUPT_NULL_NULL","text":{"KOREA":"크윽?","JPN":"くっ！？","ENG":"Kgh?","TWN":"咳呃？"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINISTRA_CORRUPT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_COMBAT_MONSTER_MINISTRA_DAMAGE_DOWN_02"},{"id":"L20_1","type":"dialog","speaker":"MINISTRA_CORRUPT_NULL_NULL","text":{"KOREA":"이 미물들이… 내 아름다운 육신에 상처를 내?","JPN":"微物どもが……余の美しい肉体に傷をつけるか。","ENG":"You vermin... dared mar my beautiful flesh?","TWN":"這些渺小的人類…居然弄傷我美麗的肉身？"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINISTRA_CORRUPT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"마사키. 연계할 때 이름을 외칠 필요가 있었어?","JPN":"雅紀、連携する時名前を叫ぶ必要はなかったんじゃない？","ENG":"Masaki, did you need to shout my name mid-combo?","TWN":"雅紀，連接的時候有必要喊名字嗎？"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"이러면 기습의 의미가 없잖아.","JPN":"これじゃ不意打ちの意味がないだろ。","ENG":"Kinda ruins the ambush.","TWN":"這樣突襲就沒有意義了啊。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"쳇. 난 당연히 네가 <color=#ffd34c>아홉 개의 태양</color>을 쓸 줄 알았지.","JPN":"ちっ。オレ様は当然、<color=#ffd34c>九つの太陽</color>を使うと思ったんだよ。","ENG":"Tch. I figured you'd use the <color=#ffd34c>Nine Suns</color>.","TWN":"嘖，我以為你當然會使出<color=#ffd34c>九重天陽</color>。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L27_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"모처럼의 재등장인데 필살기 정도는 날리라고.","JPN":"せっかくの再登場だから必殺技ぐらい使えって。","ENG":"Big comeback deserves a finisher.","TWN":"難得再次登場，至少要使出必殺技。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"오로치에게 사용했던 기술은 못쓴다고 벌써 열 번은 말했어.","JPN":"オロチに使った技はもう使えないって10回は言った。","ENG":"Told you ten times that I can't use the move I used on Orochi.","TWN":"我已經說過十次沒辦法使出在大蛇身上用過的技能了。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"MINISTRA_CORRUPT_NULL_NULL","text":{"KOREA":"네놈들이… 나를 무시해?","JPN":"貴様ら……よくも余を無視したな。","ENG":"You... dare ignore me?","TWN":"你們這些傢伙…是無視我嗎？"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINISTRA_CORRUPT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_COMBAT_MONSTER_MINISTRA_DAMAGE_DOWN_02"},{"id":"L31_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"뭐…….","JPN":"まあ……","ENG":"Well...","TWN":"嗯……"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"태양은 무리더라도, 건물 외벽정도는 떨굴 수 있지만.","JPN":"太陽は無理でも、建物の外壁ぐらいは落とせるけどな。","ENG":"I can't drop suns, but I can drop an exterior wall.","TWN":"就算無法對付太陽，但至少能打倒建築外牆。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"MINISTRA_CORRUPT_NULL_NULL","text":{"KOREA":"이건…?","JPN":"これは……？","ENG":"This is...?","TWN":"這是…？"},"stage":{"bg":"BLACK","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINISTRA_CORRUPT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"가뒀어, 마사키.","JPN":"閉じ込めたよ、雅紀。","ENG":"I've got her, Masaki.","TWN":"關起來了，雅紀。"},"stage":{"bg":"BLACK","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"MINISTRA_CORRUPT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"그래. 역시 어둠의 흑막조원다운 수행력이다.","JPN":"ああ。さすが闇の黒幕組の組員らしい遂行力だ。","ENG":"Good. Truly worthy of the Shadow Group's ace member.","TWN":"嗯，不愧是暗黑大神組組員的執行力。"},"stage":{"bg":"BLACK","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"MINISTRA_CORRUPT_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L41_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"그럼, 오오가미의 검은 불꽃을 느껴봐라-!!","JPN":"それじゃ、食らえ、大神の黒い炎ー！！","ENG":"Now, feel Ogami's black flames!!","TWN":"那就感受一下大神之劍的火花吧-！！"},"stage":{"bg":"BLACK","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"MINISTRA_CORRUPT_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L45_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"비교적 약한 침식체라 다행이다. 하마터면 위험할 뻔했어.","JPN":"比較的弱い侵食体で良かったよ。危ないところだった。","ENG":"Lucky it was a relatively weak C.O. That could've gotten dicey.","TWN":"幸好是比較弱的侵蝕體，差點就陷入危險了。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L48_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"다친 덴 없어, 아키?","JPN":"怪我はない、秋？","ENG":"Are you okay, Aki?","TWN":"廣瀨秋，妳有沒有哪裡受傷？"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L49_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"미나토 씨? 여긴 어떻게?","JPN":"湊さん？　どうしてここに？","ENG":"Minato? How are you here?","TWN":"南裕夏？你怎麼在這裡？"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"음… 말하자면 긴데.","JPN":"えーと……説明すると長くなるんだけど。","ENG":"Mm... It's a long story.","TWN":"嗯…說來話長。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"훗, 그야 우리 오오가미 흑막조가 구 관리국의 고르디우스 전대에 편입되었기 때문이지.","JPN":"ふっ、それは大神黒幕組が旧管理局のゴルディウス戦隊に編入されたからだ。","ENG":"Ha! Ogami's Shadow Group was folded into the Old Administration's Gordias Division.","TWN":"呵，那是因為我們大神組被編入舊管理局的哥帝爾斯戰隊。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"뭐야, 평소에 하던 비밀조직 놀이였군요.","JPN":"なんだ、いつもの秘密組織ごっこだったんですね。","ENG":"Oh, so the usual secret-organization LARP.","TWN":"搞什麼？原來是平時在玩的祕密組織遊戲。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"놀이가 아냐! 우린 챔버 관리국의 요청을 받고 이곳을 지원하던 참이라고!","JPN":"ごっこじゃねぇ！　オレ様たちは管理局に頼まれて支援に来たんだ！","ENG":"It's not a game! We came at the Chamber Administration's request!","TWN":"才不是遊戲！我們正好接受密室管理局的請求來支援這裡！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"아, 아키 양. 무사하셔서 다행이에요…….","JPN":"あ、秋さん、無事でよかったです……","ENG":"A-Aki... I'm so glad you're okay...","TWN":"啊，廣瀨秋小姐，幸好妳平安無事……"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":null}},"sfx":"FX_CUTSCEN_WIND2"},{"id":"L7_1","type":"dialog","speaker":"XIEN_FREEDOM_NULL_NULL","text":{"KOREA":"음. 설산에서 맺은 우리 우정은 한날한시에 죽는 순간까지 불멸이라네.","JPN":"うむ。雪山で誓いあった我々の友情は、共に死ぬ瞬間まで不滅だ。","ENG":"Mm. Our bond from the snowy peaks is immortal till we die the same day.","TWN":"嗯，我們在雪山結下的友誼，直到同日同時死去的那一刻都永垂不朽。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"XIEN_FREEDOM_NULL_NULL","face":"UNIT_PRIDE"}}},"sfx":"FX_CUTSCEN_WIND2"},{"id":"L9_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"아까 초코바 넘기던 거 다 봤거든요?","JPN":"さっきチョコレートバー渡してたの、見ましたからね。","ENG":"I saw you passing those chocolate bars, you know?","TWN":"你們剛才給巧克力棒我都看到了。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L10_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"정말이지…… 으윽…!!","JPN":"まったく……っ……！！","ENG":"Seriously– Ngh...!!","TWN":"真是的……呃呃…！！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"어… 설마 다친 건가요……?","JPN":"え……まさか、どこか怪我したんですか……？","ENG":"Oh... are you hurt...?","TWN":"呃…難道你受傷了嗎……？"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"XIEN_FREEDOM_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L16_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"아까 넘어지면서 다쳤나보네. 상처가 덧나기 전에 치료하는 편이 좋겠다.","JPN":"さっき転んだ時の怪我かな。悪化する前に手当したほうがよさそうだ。","ENG":"Must've gotten banged up when you fell. Better patch it before it worsens.","TWN":"看來是剛才跌倒的時候受傷了，最好在傷口發炎之前處理。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L17_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"치나츠. 부탁할 수 있을까?","JPN":"千夏、頼めるかな？","ENG":"Chinatsu, could you treat me?","TWN":"千夏，可以拜託妳嗎？"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L19_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"네. 상처를 살필 테니 잠시 손을 내어주시길.","JPN":"はい。傷の様子を確認するので、手をこちらに。","ENG":"Of course. Please give me your hand while I check the wound.","TWN":"好，我會看看傷口，請你把手伸出來一下。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L22_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"아, 감사합니다.","JPN":"あ、ありがとうございます。","ENG":"Ah, thank you.","TWN":"啊，謝謝妳。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"저기…….","JPN":"あの……","ENG":"Um...","TWN":"那個……"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"저는 나나하라 가문 연합을 이끄는 당주, 나나하라 치나츠입니다.","JPN":"私は七原家連合を率いる当主、七原千夏と申します。","ENG":"I am Nanahara Chinatsu, head of the Nanahara Family Alliance.","TWN":"我是領導七原家族聯盟的堂主，七原千夏。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"지금은 명예 흑막조원으로서 시민분들의 대피를 돕고 있어요.","JPN":"今は黒幕組の名誉組員として、市民の方々の避難をお手伝いしています。","ENG":"For now, as an honorary Shadow Group member, I'm aiding civilian evacuation.","TWN":"現在正以名譽大神組組員身分幫助市民撤離。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"…그 컨셉, 밀고 가는 거야?","JPN":"……その設定、貫くんだ？","ENG":"...We're committing to that bit?","TWN":"…是要主打這個風格嗎？"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"후후. 고르디우스 전대원이라는 것보다 이쪽이 이야기가 편하니까요.","JPN":"ふふ。ゴルディウス戦隊員を名乗るよりはこちらのほうが話しやすいですから。","ENG":"Hehe. It's easier to explain than \\"Gordias Division member.\\"","TWN":"呵呵，比起哥帝爾斯戰隊成員，這樣說比較自在。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L35_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"이렇게 어린 애가 나뭐시기 가문의, 당주…?","JPN":"こんなに若い子が、七……なんとか家の、当主……？","ENG":"A kid like you is the head of some big clan...?","TWN":"這樣的小毛頭是七什麼家族的堂主…？"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L36_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"뭐야, 이번 대원은 그런 컨셉이었군요?","JPN":"なんだ、今度の組員はそういう設定なんですね？","ENG":"Ah, so that's her lore, huh?","TWN":"搞什麼？原來這次的隊員是走這種風格啊？"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L37_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"진짜다. 바로 납득했네.","JPN":"本当だ。すぐ納得した。","ENG":"She bought it instantly. Figures.","TWN":"是真的，馬上就理解了。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L40_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"저기… 이제 안심해도 되는 걸까요…….","JPN":"あの……これで安心していいんでしょうか……","ENG":"Um... is it safe now...?","TWN":"那個…現在可以放心了嗎……"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"XIEN_FREEDOM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"네. 근처에 저희가 세운 대피소가 있으니 그쪽으로 안내해드리겠습니다.","JPN":"はい。近くに私たちが設けた避難所がありますので、そちらにご案内します。","ENG":"Yes. We set up a shelter nearby. I'll guide you there.","TWN":"嗯，附近有我們設置的避難所，我帶你們過去那裡。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"아, 저흰 괜찮으니까… 실례가 안된다면 다른 쪽을 지원해주실 수 있을까요……?","JPN":"あ、ヒミコたちは大丈夫ですから……よかったら、他の方を支援してくれませんか……？","ENG":"W-we'll be fine... If it's not rude, could you help elsewhere instead...?","TWN":"啊，我們沒關係…不介意的話，可以支援其他地方嗎……？"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"XIEN_FREEDOM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"제가 엑스트라 잡몹이라도 양심은 있다 보니, 먼저 도망친 게 조금 걸린 달까…….","JPN":"ヒミコ、影薄モブキャラだけど良心はあるので、先に逃げちゃって申し訳ないというか……","ENG":"Even as an extra mob, I still have a conscience... So running first nags at me...","TWN":"就算我是個小臨演，但還是有良心，該說是先逃跑花了點時間嗎……"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"XIEN_FREEDOM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"엑스트라 잡몹… 이 무엇인지는 모르겠으나, 다른 분들이라면 걱정하실 필요 없습니다.","JPN":"影薄モブキャラ……の意味はよくわかりませんが、他の方々ならご心配なく。","ENG":"I don't know what an \\"extra mob\\" is... but no need to worry about the others.","TWN":"小臨演…雖然不知道是什麼，但妳不用擔心其他人。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"그도 그럴 것이-.","JPN":"なにせ……","ENG":"Because...","TWN":"也是–"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"세상에서 가장 든든한 바람이, 곧 그곳에 불어올 테니까요.","JPN":"この世で一番頼もしい風が、そこに吹いてくる予定ですから。","ENG":"The strongest and kindest wind in the world is about to blow their way.","TWN":"世上最堅實的風，很快就會吹到那裡。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_NANAHARA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};